package main

import (
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig holds the saved webhook configuration
var WebhookConfig struct {
	URL string `json:"webhook_url"`
}

// RequestBody represents the POST request body structure
type RequestBody struct {
	WebhookURL string `json:"webhook_url"`
}

// ResponseBody represents the JSON response structure
type ResponseBody struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var body RequestBody
	if err := ctx.BodyParser(&body); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ResponseBody{
			Success: false,
			Message: "Invalid request body: " + err.Error(),
		})
	}

	// Validate webhook URL is not empty
	if body.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(ResponseBody{
			Success: false,
			Message: "Webhook URL is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate URL
	resp, err := client.Get(body.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ResponseBody{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if response status is successful (2xx range)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(ResponseBody{
			Success: false,
			Message: "Webhook URL returned invalid status code: " + resp.Status,
		})
	}

	// Save the configuration
	WebhookConfig.URL = body.WebhookURL

	// Return success response
	return ctx.JSON(ResponseBody{
		Success: true,
		Message: "Webhook configuration saved successfully",
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Define POST route for webhook configuration
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

