package main

import (
	"encoding/json"
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig stores the configured webhook URL
var WebhookConfig struct {
	URL string `json:"webhook_url"`
}

// RequestBody represents the expected JSON body of the POST request
type RequestBody struct {
	WebhookURL string `json:"webhook_url"`
}

// ResponseBody represents the JSON response to be returned
type ResponseBody struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var reqBody RequestBody
	if err := json.Unmarshal(ctx.Body(), &reqBody); err != nil {
		return ctx.JSON(ResponseBody{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Validate webhook URL is not empty
	if reqBody.WebhookURL == "" {
		return ctx.JSON(ResponseBody{
			Success: false,
			Message: "Webhook URL is required",
		})
	}

	// Test webhook URL with GET request and 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(reqBody.WebhookURL)
	if err != nil {
		log.Printf("Failed to test webhook URL: %v", err)
		return ctx.JSON(ResponseBody{
			Success: false,
			Message: "Failed to reach webhook URL",
		})
	}
	defer resp.Body.Close()

	// Check if response status is 2xx
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.JSON(ResponseBody{
			Success: false,
			Message: "Webhook URL returned an error status",
		})
	}

	// Save configuration
	WebhookConfig.URL = reqBody.WebhookURL

	return ctx.JSON(ResponseBody{
		Success: true,
		Message: "Webhook configuration successful",
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Define route for webhook configuration
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server
	log.Println("Server running on :3000")
	if err := app.Listen(":3000"); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

