	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
	})
}

// isLoopbackOrPrivateIP checks if a hostname resolves to a loopback or private IP address
func isLoopbackOrPrivateIP(host string) bool {
	ips, err := net.LookupIP(host)
	if err != nil {
		// If we can't resolve the hostname, assume it's invalid (to be safe)
		return true
	}

	for _, ip := range ips {
		// Check for loopback addresses
		if ip.IsLoopback() {
			return true
		}

		// Check for IPv4 private addresses (RFC 1918)
		if ip.To4() != nil {
			if (ip[0] == 10) || // 10.0.0.0/8
				(ip[0] == 172 && (ip[1] >= 16 && ip[1] <= 31)) || // 172.16.0.0/12
				(ip[0] == 192 && ip[1] == 168) { // 192.168.0.0/16
				return true
			}
			// Check for IPv4 link-local addresses (169.254.0.0/16)
			if ip[0] == 169 && ip[1] == 254 {
				return true
			}
		} else {
			// Check for IPv6 private addresses
			// IPv6 unique local addresses (fc00::/7)
			if (ip[0] == 0xfc || ip[0] == 0xfd) {
				return true
			}
			// IPv6 link-local addresses (fe80::/10)
			if (ip[0] == 0xfe && (ip[1]&0xc0) == 0x80) {
				return true
			}
		}
	}

	return false
}

