package main

import (
	"encoding/json"
	"log"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig stores the configured webhook URL
var WebhookConfig = struct {
	URL string `json:"webhook_url"`
}{}

// ConfigureWebhook handles webhook configuration requests
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var req struct {
		WebhookURL string `json:"webhook_url"`
	}
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid request body",
			"error":   err.Error(),
		})
	}

	// Validate webhook URL format and accessibility
	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Webhook URL is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate webhook
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Failed to validate webhook URL",
			"error":   err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response status is success
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Webhook URL returned an error status",
			"status":  resp.StatusCode,
		})
	}

	// Save the configuration
	WebhookConfig.URL = req.WebhookURL

	// Return success response
	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
		"config":  WebhookConfig,
	})
}

func main() {
	// Create a new Fiber instance
	app := fiber.New()

	// Register the handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server on port 3000
	log.Fatal(app.Listen(":3000"))
}

