package main

import (
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the configuration for the webhook
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Configuration storage (in-memory for this example)
var webhookConfig *WebhookConfig

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var config WebhookConfig
	if err := json.Unmarshal(ctx.Body(), &config); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid request body",
		})
	}

	// Validate webhook URL
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL is invalid or unreachable: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if response status is 2xx
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned invalid status: " + resp.Status,
		})
	}

	// Save configuration
	webhookConfig = &config

	// Return success response
	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configuration saved successfully",
		"config":  config,
	})
}

func main() {
	app := fiber.New()

	// POST endpoint for configuring webhook
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server
	app.Listen(":3000")
}

