package main

import (
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the request body structure
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Response represents the API response structure
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// savedWebhookURL stores the configured webhook URL in memory (for demo purposes)
var savedWebhookURL string

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse JSON request body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Failed to parse request body: " + err.Error(),
		})
	}

	// Validate webhook URL format
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Webhook URL is required",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate webhook URL
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if response status is successful (2xx)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Webhook URL returned invalid status code: " + resp.Status,
		})
	}

	// Save the valid configuration (in-memory storage for demo)
	savedWebhookURL = config.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Define the API endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

