package main

import (
	"context"
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the configuration for a webhook
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// In-memory storage for webhook configuration (in production, use a database)
var webhookConfig WebhookConfig

func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to parse request body",
		})
	}

	// Validate webhook URL
	if config.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL is required",
		})
	}

	// Test the webhook URL with 3-second timeout
	ctxTimeout, cancel := context.WithTimeout(context.Background(), 3*time.Second)
	defer cancel()

	req, err := http.NewRequestWithContext(ctxTimeout, http.MethodGet, config.WebhookURL, nil)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to create test request",
		})
	}

	client := &http.Client{}
	resp, err := client.Do(req)
	if err != nil {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to test webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if test request succeeded
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusInternalServerError).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned invalid status: " + resp.Status,
		})
	}

	// Save the webhook configuration
	webhookConfig = config

	// Return success response
	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
		"config":  webhookConfig,
	})
}

func main() {
	app := fiber.New()

	// Endpoint for configuring webhook
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start server (default port 3000)
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

