package main

import (
	"encoding/json"
	"fmt"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the request body for configuring webhook
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url" validate:"required,url"`
}

// ConfigResult represents the response for webhook configuration
type ConfigResult struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

var savedWebhookURL string

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse JSON body
	if err := json.Unmarshal(ctx.Body(), &config); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(ConfigResult{
			Success: false,
			Message: "Invalid request body: " + err.Error(),
		})
	}

	// Validate webhook URL format
	if config.WebhookURL == "" {
		return ctx.Status(http.StatusBadRequest).JSON(ConfigResult{
			Success: false,
			Message: "webhook_url is required",
		})
	}

	// Send test request with 3 seconds timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(ConfigResult{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if status code is 2xx
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(http.StatusBadRequest).JSON(ConfigResult{
			Success: false,
			Message: fmt.Sprintf("Webhook URL returned status code: %d", resp.StatusCode),
		})
	}

	// Save the configuration
	savedWebhookURL = config.WebhookURL

	// Return success response
	return ctx.Status(http.StatusOK).JSON(ConfigResult{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	app := fiber.New()

	// Configure webhook endpoint
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server
	if err := app.Listen(":8080"); err != nil {
		panic(err)
	}
}

