package main

import (
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig stores the configured webhook URL
var WebhookConfig struct {
	URL string `json:"webhook_url"`
}

// RequestBody represents the incoming request JSON schema
type RequestBody struct {
	WebhookURL string `json:"webhook_url"`
}

// ResponseBody represents the outgoing response JSON schema
type ResponseBody struct {
	Success bool   `json:"success"`
	Message string `json:"message,omitempty"`
	URL     string `json:"url,omitempty"`
}

// ConfigureWebhook handles the webhook configuration
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var reqBody RequestBody
	if err := ctx.BodyParser(&reqBody); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ResponseBody{
			Success: false,
			Message: "Invalid request body: " + err.Error(),
		})
	}

	// Validate webhook URL format
	if reqBody.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(ResponseBody{
			Success: false,
			Message: "Webhook URL cannot be empty",
		})
	}

	// Create HTTP client with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	// Send test GET request to validate the URL
	resp, err := client.Get(reqBody.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ResponseBody{
			Success: false,
			Message: "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response status code is successful
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(ResponseBody{
			Success: false,
			Message: "Webhook URL returned an invalid status code: " + resp.Status,
		})
	}

	// Save the configuration
	WebhookConfig.URL = reqBody.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(ResponseBody{
		Success: true,
		Message: "Webhook configured successfully",
		URL:     reqBody.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Define API route for configuring webhook
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

