package main

import (
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the configuration for the webhook
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Global variable to store the webhook configuration (for demo purposes)
var webhookConfig WebhookConfig

// ConfigureWebhook handles the POST request to configure the webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid request body",
			"error":   err.Error(),
		})
	}

	// Validate webhook URL
	client := &http.Client{
		Timeout: 3 * time.Second,
	}
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Webhook URL validation failed",
			"error":   err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if response status is successful
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Webhook URL validation failed",
			"error":   "Received non-success status code: " + resp.Status,
		})
	}

	// Save the configuration
	webhookConfig = config

	// Return success response
	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configuration saved successfully",
		"config":  webhookConfig,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Define the webhook configuration endpoint
	app.Post("/webhook/configure", ConfigureWebhook)

	// Start the server
	app.Listen(":3000")
}

