package main

import (
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the request body structure
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url" validate:"required,url"`
}

// Response represents the API response structure
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
	Data    *Data  `json:"data,omitempty"`
}

// Data contains additional response data
type Data struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigStorage stores the current webhook configuration
var ConfigStorage *WebhookConfig

func main() {
	app := fiber.New()

	app.Post("/webhook/configure", ConfigureWebhook)

	app.Listen(":8080")
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse request body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Failed to parse request body: " + err.Error(),
		})
	}

	// Validate webhook URL
	if err := validateWebhookURL(config.WebhookURL); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Webhook URL validation failed: " + err.Error(),
		})
	}

	// Save configuration
	ConfigStorage = &config

	// Return success response
	return ctx.Status(http.StatusOK).JSON(Response{
		Success: true,
		Message: "Webhook configuration saved successfully",
		Data: &Data{
			WebhookURL: config.WebhookURL,
		},
	})
}

func validateWebhookURL(url string) error {
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	_, err := client.Get(url)
	if err != nil {
		return err
	}

	return nil
}

