package main

import (
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the configuration data for a webhook
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Global variable to store webhook configuration
var webhookConfig WebhookConfig

func main() {
	app := fiber.New()

	// Define the endpoint for configuring the webhook
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

// ConfigureWebhook handles the webhook configuration request
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var req WebhookConfig
	if err := json.Unmarshal(ctx.Body(), &req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Invalid request body",
			"error":   err.Error(),
		})
	}

	// Validate webhook URL by sending a test GET request with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	_, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"message": "Failed to validate webhook URL",
			"error":   err.Error(),
		})
	}

	// Save the webhook configuration
	webhookConfig = req

	// Return success response
	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
		"config":  webhookConfig,
	})
}

