package main

import (
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the incoming request body structure
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// SavedWebhookConfig stores the validated webhook configuration
var SavedWebhookConfig *WebhookConfig

// ConfigureWebhook handles POST requests to configure webhooks
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var config WebhookConfig
	if err := json.Unmarshal(ctx.Body(), &config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid request body",
		})
	}

	// Validate webhook URL by sending a test GET request
	client := &http.Client{
		Timeout: 3 * time.Second,
	}
	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to reach webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response is successful (2xx status code)
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned invalid status code: " + resp.Status,
		})
	}

	// Save the valid configuration
	SavedWebhookConfig = &config

	// Return success response
	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
		"config":  SavedWebhookConfig,
	})
}

func main() {
	app := fiber.New()

	// Register the handler
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

