			"success": false,
			"error":   "webhook_url is required",
		})
	}

	// Validate URL format
	parsedURL, err := url.ParseRequestURI(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Invalid webhook URL format",
		})
	}

	// Ensure the URL has a valid scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "webhook URL must use http or https scheme",
		})
	}

	// Validate host and port
	host, _, err := net.SplitHostPort(parsedURL.Host)
	if err != nil {
		// If no port is specified, SplitHostPort returns an error. So use the entire Host as host.
		host = parsedURL.Host
	}

	// Resolve host to IP addresses to check for loopback or private IPs
	ips, err := net.LookupIP(host)
	if err != nil {
