    "net/http"
    "time"
)

type WebhookConfig struct {
    WebhookURL string `json:"webhook_url"`
}

// In-memory storage for configuration (for demonstration purposes)
var storedConfig *WebhookConfig

func ConfigureWebhook(ctx *fiber.Ctx) error {
    var config WebhookConfig

    // Parse request body
    if err := ctx.BodyParser(&config); err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "success": false,
            "error":   "Failed to parse request body",
        })
    }

    // Validate webhook URL by sending a test request with 3-second timeout
    client := &http.Client{
        Timeout: 3 * time.Second,
    }

    resp, err := client.Get(config.WebhookURL)
    if err != nil {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "success": false,
            "error":   "Invalid webhook URL: " + err.Error(),
        })
    }
    defer resp.Body.Close()

    // Check if the response is successful (2xx status code)
    if resp.StatusCode < 200 || resp.StatusCode >= 300 {
        return ctx.Status(fiber.StatusBadRequest).JSON(fiber.Map{
            "success": false,
            "error":   "Invalid webhook URL: received status code " + resp.Status,
        })
    }

    // Save configuration
    storedConfig = &config

    return ctx.JSON(fiber.Map{
        "success": true,
        "message": "Webhook configured successfully",
        "config":  storedConfig,
    })
}

func main() {
    app := fiber.New()

    app.Post("/configure-webhook", ConfigureWebhook)

    // Start server on port 3000
    if err := app.Listen(":3000"); err != nil {
        panic(err)
    }
}

