package main

import (
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig stores the configured webhook URL
var WebhookConfig struct {
	URL string `json:"webhook_url"`
}

// ConfigureWebhookRequest represents the incoming request body
type ConfigureWebhookRequest struct {
	WebhookURL string `json:"webhook_url"`
}

// ConfigureWebhookResponse represents the outgoing response
type ConfigureWebhookResponse struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
	URL     string `json:"webhook_url,omitempty"`
}

// ConfigureWebhook handles the POST request to configure a webhook
func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse and validate incoming request
	var req ConfigureWebhookRequest
	if err := ctx.BodyParser(&req); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Failed to parse request body: " + err.Error(),
		})
	}

	if req.WebhookURL == "" {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Webhook URL is required",
		})
	}

	// Validate webhook URL by sending a test GET request with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}
	resp, err := client.Get(req.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
			URL:     req.WebhookURL,
		})
	}
	defer resp.Body.Close()

	// Check if we got a successful status code
	if resp.StatusCode < 200 || resp.StatusCode >= 400 {
		return ctx.Status(fiber.StatusBadRequest).JSON(ConfigureWebhookResponse{
			Success: false,
			Message: "Webhook URL returned status code: " + resp.Status,
			URL:     req.WebhookURL,
		})
	}

	// Save the configuration
	WebhookConfig.URL = req.WebhookURL

	// Return success response
	return ctx.Status(fiber.StatusOK).JSON(ConfigureWebhookResponse{
		Success: true,
		Message: "Webhook configured successfully",
		URL:     req.WebhookURL,
	})
}

func main() {
	// Initialize Fiber app
	app := fiber.New()

	// Define routes
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start server
	if err := app.Listen(":8080"); err != nil {
		panic(err)
	}
}

