package main

import (
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig stores the configured webhook URL
var webhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// RequestBody represents the JSON body structure for the POST request
type RequestBody struct {
	WebhookURL string `json:"webhook_url"`
}

// ResponseBody represents the JSON response structure
type ResponseBody struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
	Data    struct {
		WebhookURL string `json:"webhook_url"`
	} `json:"data"`
}

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var reqBody RequestBody
	if err := ctx.BodyParser(&reqBody); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(ResponseBody{
			Success: false,
			Message: "Invalid JSON body",
		})
	}

	// Validate webhook URL format and accessibility
	client := &http.Client{
		Timeout: 3 * time.Second, // 3-second timeout as required
	}

	_, err := client.Get(reqBody.WebhookURL)
	if err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(ResponseBody{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}

	// Save configuration
	webhookConfig.WebhookURL = reqBody.WebhookURL

	// Return success response
	return ctx.JSON(ResponseBody{
		Success: true,
		Message: "Webhook configured successfully",
		Data: struct {
			WebhookURL string `json:"webhook_url"`
		}{
			WebhookURL: webhookConfig.WebhookURL,
		},
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server on port 3000
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

