package main

import (
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the request body structure
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// Response represents the JSON response structure
type Response struct {
	Success bool   `json:"success"`
	Message string `json:"message"`
}

// global variable to store the webhook configuration
var savedWebhookURL string

func ConfigureWebhook(ctx *fiber.Ctx) error {
	// Parse request body
	var config WebhookConfig
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Failed to parse request body: " + err.Error(),
		})
	}

	// Validate webhook URL by sending a test GET request with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}
	_, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(fiber.StatusBadRequest).JSON(Response{
			Success: false,
			Message: "Failed to validate webhook URL: " + err.Error(),
		})
	}

	// Save the configuration
	savedWebhookURL = config.WebhookURL

	// Return success response
	return ctx.JSON(Response{
		Success: true,
		Message: "Webhook configured successfully",
	})
}

func main() {
	// Create a new Fiber instance
	app := fiber.New()

	// Register the ConfigureWebhook handler for POST requests at /configure-webhook
	app.Post("/configure-webhook", ConfigureWebhook)

	// Start the server on port 3000
	app.Listen(":3000")
}

