package main

import (
	"encoding/json"
	"net/http"
	"time"

	"github.com/gofiber/fiber/v2"
)

// WebhookConfig represents the request body structure
type WebhookConfig struct {
	WebhookURL string `json:"webhook_url"`
}

// StoredWebhookConfig holds the saved webhook configuration
var StoredWebhookConfig string

func ConfigureWebhook(ctx *fiber.Ctx) error {
	var config WebhookConfig

	// Parse JSON body
	if err := ctx.BodyParser(&config); err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to parse request body: " + err.Error(),
		})
	}

	// Validate webhook URL by sending a test GET request with 3-second timeout
	client := &http.Client{
		Timeout: 3 * time.Second,
	}

	resp, err := client.Get(config.WebhookURL)
	if err != nil {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Failed to validate webhook URL: " + err.Error(),
		})
	}
	defer resp.Body.Close()

	// Check if the response status code is in 2xx range
	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		return ctx.Status(http.StatusBadRequest).JSON(fiber.Map{
			"success": false,
			"error":   "Webhook URL returned invalid status code: " + resp.Status,
		})
	}

	// Save the configuration
	StoredWebhookConfig = config.WebhookURL

	// Return success response
	return ctx.JSON(fiber.Map{
		"success": true,
		"message": "Webhook configured successfully",
		"webhook_url": config.WebhookURL,
	})
}

func main() {
	app := fiber.New()

	app.Post("/configure-webhook", ConfigureWebhook)

	// Optional: Add a GET endpoint to retrieve the saved configuration
	app.Get("/webhook-config", func(ctx *fiber.Ctx) error {
		return ctx.JSON(fiber.Map{
			"webhook_url": StoredWebhookConfig,
		})
	})

	// Start server
	if err := app.Listen(":3000"); err != nil {
		panic(err)
	}
}

